import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { workflowApi, runApi, analyticsApi } from '../api/client';
import { Workflow, WorkflowRun } from '../types';
import { StatusBadge } from '../components/shared/StatusBadge';
import { formatRelativeTime } from '../utils/time';

export function DashboardPage() {
  const navigate = useNavigate();
  const [workflows, setWorkflows] = useState<Workflow[]>([]);
  const [recentRuns, setRecentRuns] = useState<WorkflowRun[]>([]);
  const [stats, setStats] = useState<Record<string, number>>({});
  const [cost, setCost] = useState<{ totalCost: number; totalTokens: number } | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      workflowApi.list(),
      runApi.list(),
      analyticsApi.runStats(),
      analyticsApi.cost(30),
    ]).then(([wRes, rRes, sRes, cRes]) => {
      setWorkflows(wRes.workflows.slice(0, 5));
      setRecentRuns(rRes.runs.slice(0, 8));
      const statsMap: Record<string, number> = {};
      sRes.stats.forEach((s) => { statsMap[s.status] = s._count.id; });
      setStats(statsMap);
      setCost(cRes);
    }).finally(() => setLoading(false));
  }, []);

  const totalRuns = Object.values(stats).reduce((a, b) => a + b, 0);

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Dashboard</h1>
          <p className="page-subtitle">Overview of your AI workflow automations</p>
        </div>
        <div className="page-actions">
          <button className="btn btn-primary" id="new-workflow-btn" onClick={() => navigate('/builder/new')}>
            ⚡ New Workflow
          </button>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-label">Total Workflows</div>
          <div className="stat-value">{loading ? '—' : workflows.length}</div>
          <div className="stat-sub">Across all projects</div>
          <div className="stat-icon">⚡</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Total Runs</div>
          <div className="stat-value">{loading ? '—' : totalRuns}</div>
          <div className="stat-sub">All time</div>
          <div className="stat-icon">▶</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Success Rate</div>
          <div className="stat-value" style={{ color: 'var(--color-success)' }}>
            {loading || !totalRuns ? '—' : `${Math.round(((stats.COMPLETED ?? 0) / totalRuns) * 100)}%`}
          </div>
          <div className="stat-sub">{stats.COMPLETED ?? 0} completed</div>
          <div className="stat-icon">✓</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Active Runs</div>
          <div className="stat-value" style={{ color: 'var(--color-info)' }}>
            {loading ? '—' : (stats.RUNNING ?? 0)}
          </div>
          <div className="stat-sub">Currently running</div>
          <div className="stat-icon">🔄</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Pending Approval</div>
          <div className="stat-value" style={{ color: 'var(--color-human)' }}>
            {loading ? '—' : (stats.WAITING_HUMAN ?? 0)}
          </div>
          <div className="stat-sub">Waiting for human</div>
          <div className="stat-icon">👤</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">AI Cost (30d)</div>
          <div className="stat-value" style={{ color: 'var(--color-brand-accent)' }}>
            {loading || !cost ? '—' : `$${cost.totalCost.toFixed(4)}`}
          </div>
          <div className="stat-sub">{cost ? `${(cost.totalTokens / 1000).toFixed(1)}k tokens` : ''}</div>
          <div className="stat-icon">💰</div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-5)' }}>
        {/* Recent Workflows */}
        <div className="card">
          <div className="flex items-center justify-between" style={{ marginBottom: 'var(--space-4)' }}>
            <h3>Workflows</h3>
            <button className="btn btn-secondary btn-sm" onClick={() => navigate('/workflows')}>View All</button>
          </div>
          {loading ? (
            <div className="flex flex-col gap-3">
              {[1,2,3].map(i => <div key={i} className="skeleton" style={{ height: 40 }} />)}
            </div>
          ) : workflows.length === 0 ? (
            <div className="empty-state" style={{ padding: 'var(--space-8)' }}>
              <div className="empty-icon">⚡</div>
              <div className="empty-title">No workflows yet</div>
              <button className="btn btn-primary btn-sm" onClick={() => navigate('/builder/new')}>Create your first</button>
            </div>
          ) : (
            <div className="flex flex-col gap-2">
              {workflows.map((wf) => (
                <div
                  key={wf.id}
                  className="flex items-center gap-3"
                  style={{ padding: 'var(--space-2) var(--space-3)', borderRadius: 'var(--radius-md)', cursor: 'pointer', transition: 'background var(--transition-fast)' }}
                  onClick={() => navigate(`/workflows/${wf.id}`)}
                  onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.03)')}
                  onMouseLeave={(e) => (e.currentTarget.style.background = '')}
                >
                  <div style={{ width: 32, height: 32, borderRadius: 'var(--radius-md)', background: 'linear-gradient(135deg, var(--color-brand-primary), var(--color-brand-secondary))', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14, flexShrink: 0 }}>⚡</div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div className="truncate" style={{ fontWeight: 500, fontSize: '0.875rem' }}>{wf.name}</div>
                    <div className="text-muted text-sm">{wf.triggerType}</div>
                  </div>
                  <StatusBadge status={wf.versions[0]?.status ?? 'DRAFT'} />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recent Runs */}
        <div className="card">
          <div className="flex items-center justify-between" style={{ marginBottom: 'var(--space-4)' }}>
            <h3>Recent Runs</h3>
            <button className="btn btn-secondary btn-sm" onClick={() => navigate('/runs')}>View All</button>
          </div>
          {loading ? (
            <div className="flex flex-col gap-3">
              {[1,2,3].map(i => <div key={i} className="skeleton" style={{ height: 40 }} />)}
            </div>
          ) : recentRuns.length === 0 ? (
            <div className="empty-state" style={{ padding: 'var(--space-8)' }}>
              <div className="empty-icon">▶</div>
              <div className="empty-title">No runs yet</div>
              <div className="empty-desc">Trigger a workflow to see runs here</div>
            </div>
          ) : (
            <div className="flex flex-col gap-1">
              {recentRuns.map((run) => (
                <div
                  key={run.id}
                  className="flex items-center gap-3"
                  style={{ padding: 'var(--space-2) var(--space-3)', borderRadius: 'var(--radius-md)', cursor: 'pointer', transition: 'background var(--transition-fast)' }}
                  onClick={() => navigate(`/runs/${run.id}`)}
                  onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(255,255,255,0.03)')}
                  onMouseLeave={(e) => (e.currentTarget.style.background = '')}
                >
                  <StatusBadge status={run.status} dot />
                  <div className="flex-col" style={{ flex: 1, minWidth: 0 }}>
                    <div className="truncate text-sm font-mono" style={{ color: 'var(--color-text-secondary)' }}>
                      {run.id.split('-')[0]}...
                    </div>
                  </div>
                  <div className="text-muted text-sm">{formatRelativeTime(run.startedAt)}</div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
