import React, { useState } from 'react';
import { authApi } from '../api/client';
import { useAuth } from '../context/AuthContext';

export function LoginPage() {
  const { login } = useAuth();
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [form, setForm] = useState({
    email: '', password: '', name: '', tenantName: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      let res;
      if (mode === 'login') {
        res = await authApi.login(form.email, form.password);
      } else {
        res = await authApi.register({ email: form.email, password: form.password, name: form.name, tenantName: form.tenantName });
      }
      login(res.user, res.accessToken, res.refreshToken);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  const set = (field: string) => (e: React.ChangeEvent<HTMLInputElement>) =>
    setForm((f) => ({ ...f, [field]: e.target.value }));

  return (
    <div className="login-page">
      <div className="login-bg">
        <div className="login-orb login-orb-1" />
        <div className="login-orb login-orb-2" />
        <div className="login-orb login-orb-3" />
      </div>

      <div className="login-card card-glass">
        {/* Logo */}
        <div className="login-logo">
          <div className="sidebar-logo-icon" style={{ width: 48, height: 48, fontSize: 24, margin: '0 auto' }}>⚡</div>
          <h1 className="gradient-text" style={{ fontSize: '1.5rem', marginTop: 12 }}>AIWF Platform</h1>
          <p className="text-muted" style={{ fontSize: '0.875rem', marginTop: 4 }}>
            Enterprise AI Workflow Automation
          </p>
        </div>

        {/* Tabs */}
        <div className="login-tabs">
          <button
            className={`login-tab ${mode === 'login' ? 'active' : ''}`}
            onClick={() => { setMode('login'); setError(''); }}
          >Sign In</button>
          <button
            className={`login-tab ${mode === 'register' ? 'active' : ''}`}
            onClick={() => { setMode('register'); setError(''); }}
          >Create Account</button>
        </div>

        <form onSubmit={handleSubmit}>
          {mode === 'register' && (
            <>
              <div className="form-group">
                <label className="form-label">Organization Name</label>
                <input className="form-control" placeholder="Acme Corp" value={form.tenantName} onChange={set('tenantName')} required />
              </div>
              <div className="form-group">
                <label className="form-label">Your Name</label>
                <input className="form-control" placeholder="Jane Doe" value={form.name} onChange={set('name')} required />
              </div>
            </>
          )}
          <div className="form-group">
            <label className="form-label">Email</label>
            <input className="form-control" type="email" placeholder="you@company.com" value={form.email} onChange={set('email')} required />
          </div>
          <div className="form-group">
            <label className="form-label">Password</label>
            <input className="form-control" type="password" placeholder="••••••••" value={form.password} onChange={set('password')} required minLength={8} />
          </div>

          {error && (
            <div className="toast toast-error" style={{ position: 'static', marginBottom: 16, animation: 'none' }}>
              ⚠️ {error}
            </div>
          )}

          <button className="btn btn-primary w-full btn-lg" type="submit" disabled={loading} id="login-submit-btn">
            {loading ? <span className="spinner" /> : mode === 'login' ? 'Sign In →' : 'Create Account →'}
          </button>
        </form>

        <p className="text-muted" style={{ textAlign: 'center', marginTop: 20, fontSize: '0.8rem' }}>
          {mode === 'login'
            ? 'Demo: register a new account to get started'
            : 'Your account will have Admin access to your organization'}
        </p>
      </div>

      <style>{`
        .login-page {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          position: relative;
          overflow: hidden;
          background: var(--color-bg-base);
        }
        .login-bg { position: absolute; inset: 0; pointer-events: none; }
        .login-orb {
          position: absolute;
          border-radius: 50%;
          filter: blur(80px);
          opacity: 0.15;
        }
        .login-orb-1 { width: 600px; height: 600px; background: var(--color-brand-primary); top: -200px; left: -200px; }
        .login-orb-2 { width: 400px; height: 400px; background: var(--color-brand-secondary); bottom: -100px; right: -100px; }
        .login-orb-3 { width: 300px; height: 300px; background: var(--color-brand-accent); top: 50%; right: 20%; }
        .login-card {
          position: relative;
          z-index: 1;
          width: 100%;
          max-width: 420px;
          padding: 40px;
          border-radius: 24px;
        }
        .login-logo { text-align: center; margin-bottom: 32px; }
        .login-tabs {
          display: flex;
          background: var(--color-bg-overlay);
          border-radius: var(--radius-md);
          padding: 4px;
          margin-bottom: 24px;
        }
        .login-tab {
          flex: 1;
          padding: 8px;
          border: none;
          background: transparent;
          color: var(--color-text-muted);
          font-size: 0.875rem;
          font-weight: 500;
          cursor: pointer;
          border-radius: var(--radius-md);
          transition: all var(--transition-fast);
          font-family: var(--font-sans);
        }
        .login-tab.active {
          background: var(--color-bg-elevated);
          color: var(--color-text-primary);
          box-shadow: var(--shadow-sm);
        }
      `}</style>
    </div>
  );
}
